function showToast(msg) {
  let t = document.getElementById('toast');
  if (!t) {
    t = document.createElement('div');
    t.id = 'toast';
    t.style.cssText = 'position:fixed;bottom:5rem;left:50%;transform:translateX(-50%);background:hsla(215,50%,8%,0.95);border:1px solid hsl(153,100%,50%);color:hsl(153,100%,50%);font-family:JetBrains Mono,monospace;font-size:0.65rem;letter-spacing:0.15em;padding:0.5rem 1.25rem;z-index:9999;pointer-events:none;transition:opacity 0.3s;';
    document.body.appendChild(t);
  }
  t.textContent = msg; t.style.opacity = '1';
  clearTimeout(t._tid);
  t._tid = setTimeout(() => { t.style.opacity = '0'; }, 2200);
}

// ======================== CUSTOM CURSOR ========================
(function() {
  const cursor = document.getElementById('cursor');
  const svg    = document.getElementById('cursor-svg');
  let   hovering = false;
  window.addEventListener('mousemove', e => {
    cursor.style.left = e.clientX + 'px';
    cursor.style.top  = e.clientY + 'px';
  });
  window.addEventListener('mouseover', e => {
    const h = !!e.target.closest('a,button,[role="button"],input,textarea,select,[data-interactive]');
    if (h === hovering) return;
    hovering = h;
    const size = h ? 48 : 32, ll = h ? 8 : 5, c = size / 2;
    svg.setAttribute('width', size); svg.setAttribute('height', size);
    svg.setAttribute('viewBox', `0 0 ${size} ${size}`);
    svg.querySelector('circle').setAttribute('cx', c);
    svg.querySelector('circle').setAttribute('cy', c);
    const coords = { top:[c,c-4,c,c-4-ll], bottom:[c,c+4,c,c+4+ll], left:[c-4,c,c-4-ll,c], right:[c+4,c,c+4+ll,c] };
    Object.entries(coords).forEach(([id,[x1,y1,x2,y2]]) => {
      const el = document.getElementById('c-'+id);
      el.setAttribute('x1',x1); el.setAttribute('y1',y1);
      el.setAttribute('x2',x2); el.setAttribute('y2',y2);
    });
  });
})();

// ======================== PARTICLES ========================
(function() {
  const canvas = document.getElementById('particle-canvas');
  const ctx    = canvas.getContext('2d');
  let   ps     = [];
  function resize() { canvas.width = window.innerWidth; canvas.height = window.innerHeight; }
  resize(); window.addEventListener('resize', resize, { passive:true });
  const count = Math.min(80, Math.floor(window.innerWidth / 20));
  for (let i = 0; i < count; i++)
    ps.push({ x:Math.random()*canvas.width, y:Math.random()*canvas.height,
              vx:(Math.random()-0.5)*0.3,   vy:(Math.random()-0.5)*0.3,
              size:Math.random()*1.5+0.5 });
  function draw() {
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    ps.forEach((p, i) => {
      p.x += p.vx; p.y += p.vy;
      if (p.x < 0) p.x = canvas.width;  if (p.x > canvas.width)  p.x = 0;
      if (p.y < 0) p.y = canvas.height; if (p.y > canvas.height) p.y = 0;
      ctx.beginPath(); ctx.arc(p.x, p.y, p.size, 0, Math.PI*2);
      ctx.fillStyle = 'rgba(0,255,136,0.3)'; ctx.fill();
      for (let j = i+1; j < ps.length; j++) {
        const dx = p.x-ps[j].x, dy = p.y-ps[j].y, d = Math.sqrt(dx*dx+dy*dy);
        if (d < 120) {
          ctx.beginPath(); ctx.moveTo(p.x,p.y); ctx.lineTo(ps[j].x,ps[j].y);
          ctx.strokeStyle = `rgba(0,255,136,${0.08*(1-d/120)})`; ctx.lineWidth=0.5; ctx.stroke();
        }
      }
    });
    requestAnimationFrame(draw);
  }
  draw();
})();

