// ======================== ANIMATED STAT COUNTERS ========================
const STAT_TARGETS = [
  { id:'stat-projects', target:20, suffix:'+' },
  { id:'stat-tools',    target:10, suffix:'+' },
  { id:'stat-fields',   target:5,  suffix:''  },
  { id:'stat-status',   target:null, text:'ONLINE' }
];
function initCounters() {
  const observer = new IntersectionObserver(entries => {
    entries.forEach(entry => {
      if (!entry.isIntersecting) return;
      STAT_TARGETS.forEach(s => {
        const el = document.getElementById(s.id);
        if (!el) return;
        if (s.target === null) { el.textContent = s.text; return; }
        let cur = 0;
        const step = Math.ceil(s.target / 40);
        const iv = setInterval(() => {
          cur = Math.min(cur + step, s.target);
          el.textContent = cur + s.suffix;
          if (cur >= s.target) clearInterval(iv);
        }, 40);
      });
      observer.disconnect();
    });
  }, { threshold: 0.5 });
  const heroTarget = document.querySelector('.hero-stats-row') || document.querySelector('.hero-right') || document.querySelector('#hero');
  if (heroTarget) observer.observe(heroTarget);
}

