const SKILL_GROUPS = [
  { label:'LANGUAGES',  skills:[{name:'Python',level:92},{name:'HTML',level:88},{name:'C#',level:80},{name:'JavaScript',level:90}] },
  { label:'FRAMEWORKS', skills:[{name:'React / Next.js',level:90},{name:'Unity',level:82},{name:'CustomTkinter',level:75},{name:'React Native',level:78}] },
  { label:'TOOLS',      skills:[{name:'Git / GitHub',level:95},{name:'Cinemachine',level:70},{name:'Figma',level:85}] }
];
function renderSkills() {
  document.getElementById('skill-groups').innerHTML = SKILL_GROUPS.map(g => `
    <div class="skill-group">
      <p class="skill-group-label">${g.label}</p>
      ${g.skills.map((s,i) => `
        <div class="skill-row" style="transition-delay:${i*0.1}s;" data-skill-row>
          <span class="skill-name">${s.name}</span>
          <div class="skill-bar-wrap">
            <div class="skill-bar-bg"></div>
            <div class="skill-bar-fill" data-level="${s.level}"></div>
          </div>
          <span class="skill-level">${s.level}%</span>
        </div>`).join('')}
    </div>`).join('');
}
function initSkillBarObserver() {
  const obs = new IntersectionObserver(entries => {
    entries.forEach(e => {
      if (!e.isIntersecting) return;
      e.target.classList.add('visible');
      const bar = e.target.querySelector('.skill-bar-fill');
      if (bar) bar.style.width = bar.dataset.level + '%';
      obs.unobserve(e.target);
    });
  }, { threshold:0.1 });
  document.querySelectorAll('[data-skill-row]').forEach(r => obs.observe(r));
}




// ======================== TERMINAL ========================
const TERMINAL_LINES = [
  '$ whoami','Muhammad.Tayyab — developer','',
  '$ cat skills.json','{',
  '  "focus": ["web", "mobile", "games", "ML"],',
  '  "passion": "building the future",',
  '  "status": "always shipping"',
  '}','',
  '$ git log --oneline -3',
  'a1b2c3d — feat: neural network optimizer',
  'e4f5g6h — fix: multiplayer sync lag',
  'i7j8k9l — deploy: v2.0 portfolio'
];
function initTerminal() {
  const body = document.getElementById('terminal-body');
  let li=0, ci=0, cur=''; const lines=[];
  function render() {
    body.innerHTML =
      lines.map(l=>`<div class="${l.startsWith('$')?'terminal-line-cmd':'terminal-line'}">${l||' '}</div>`).join('')+
      (cur?`<div class="${cur.startsWith('$')?'terminal-line-cmd':'terminal-line'}">${cur}<span class="terminal-cursor cursor-blink"></span></div>`
          :'<span class="terminal-cursor cursor-blink"></span>');
    body.scrollTop = body.scrollHeight;
  }
  render();
  const iv = setInterval(() => {
    if (li >= TERMINAL_LINES.length) { clearInterval(iv); return; }
    const line = TERMINAL_LINES[li];
    if (ci < line.length) { cur += line[ci++]; } else { lines.push(cur); cur=''; ci=0; li++; }
    render();
  }, 50);
}

// ======================== CONTACT FORM ========================
function initContactForm() {
  const form = document.getElementById('contact-form');
  if (!form) return;
  form.addEventListener('submit', e => {
    e.preventDefault();
    let valid = true;
    const fields = [
      { id:'cf-name',    min:2,   msg:'Name must be at least 2 characters' },
      { id:'cf-email',   regex:/^[^\s@]+@[^\s@]+\.[^\s@]+$/, msg:'Enter a valid email address' },
      { id:'cf-message', min:10,  msg:'Message must be at least 10 characters' }
    ];
    fields.forEach(f => {
      const el  = document.getElementById(f.id);
      const err = document.getElementById(f.id+'-err');
      el.classList.remove('error');
      let ok = true;
      if (f.regex  && !f.regex.test(el.value.trim()))       ok = false;
      if (f.min    && el.value.trim().length < f.min)        ok = false;
      if (!ok) { el.classList.add('error'); err.textContent = f.msg; valid = false; }
      else     { err.textContent = ''; }
    });
    if (!valid) return;
    const btn = document.getElementById('cf-submit');
    btn.textContent = 'SENDING...'; btn.classList.add('loading'); btn.disabled = true;
    fetch('https://formspree.io/f/mqeywoob', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Accept': 'application/json' },
      body: JSON.stringify({
        name:    document.getElementById('cf-name').value.trim(),
        email:   document.getElementById('cf-email').value.trim(),
        message: document.getElementById('cf-message').value.trim()
      })
    })
    .then(res => res.json())
    .then(data => {
      btn.classList.remove('loading'); btn.disabled = false;
      if (data.ok) {
        document.getElementById('form-success').classList.add('show');
        form.reset();
        btn.textContent = 'SEND MESSAGE';
      } else {
        btn.textContent = 'SEND MESSAGE';
        showToast('Something went wrong. Please try again.');
      }
    })
    .catch(() => {
      btn.classList.remove('loading'); btn.disabled = false;
      btn.textContent = 'SEND MESSAGE';
      showToast('Network error. Please try again.');
    });
  });
}

// ======================== CLICK TO COPY ========================
function copyContact(value, btn) {
  navigator.clipboard.writeText(value).then(() => {
    const orig = btn.textContent;
    btn.textContent = 'COPIED ✓'; btn.classList.add('copied');
    setTimeout(() => { btn.textContent = orig; btn.classList.remove('copied'); }, 2000);
  }).catch(() => showToast('Copy failed'));
}

// ======================== SCROLL REVEAL ========================
function initScrollReveal() {
  const obs = new IntersectionObserver(entries => {
    entries.forEach(e => {
      if (e.isIntersecting) { e.target.classList.add('revealed'); obs.unobserve(e.target); }
    });
  }, { threshold:0.1 });
  document.querySelectorAll('.reveal-section').forEach(el => obs.observe(el));
}



// ======================== PAGE TRANSITION + PROJECT DETAIL ========================
function openProject(id) {
  // Smooth fade-out then navigate to separate project page
  const overlay = document.getElementById('page-transition');
  overlay.style.transition = 'opacity 0.35s ease';
  overlay.style.opacity = '1';
  overlay.style.pointerEvents = 'all';
  setTimeout(() => {
    window.location.href = 'project-' + id + '.html';
  }, 360);
}

function showProjectDetail(id) {
  const p = PROJECTS.find(x => x.id === id);
  if (!p) return;
  document.getElementById('detail-path').textContent    = p.path;
  document.getElementById('detail-tag').textContent     = '>> ' + p.path;
  document.getElementById('detail-title').textContent   = p.title;
  document.getElementById('detail-summary').textContent = p.summary;
  document.getElementById('detail-thumb-img').src       = p.image;
  document.getElementById('detail-tags').innerHTML      = p.tags.map(t=>`<span class="detail-tag">${t}</span>`).join('');
  document.getElementById('detail-main').innerHTML = `
    <p class="detail-section-label">&gt;&gt; PROJECT_OVERVIEW</p>
    ${p.description.map(d=>`<p class="detail-para">${d}</p>`).join('')}
    <p class="detail-section-label" style="margin-top:3rem;">&gt;&gt; CHALLENGES</p>
    <p class="detail-para">${p.challenges}</p>
    <p class="detail-section-label" style="margin-top:3rem;">&gt;&gt; OUTCOME</p>
    <p class="detail-para">${p.outcome}</p>`;
  document.getElementById('detail-features').innerHTML  = p.features.map(f=>`<div class="feature-item"><span class="feature-arrow">▸</span>${f}</div>`).join('');
  document.getElementById('detail-stack').innerHTML     = p.tags.map(t=>`<span class="detail-tag">${t}</span>`).join('');
  document.getElementById('main-page').style.display    = 'none';
  document.getElementById('project-detail').classList.add('active');
  window.scrollTo(0, 0);
}

function showMainPage() {
  // Show loading screen when returning, then reveal main page
  document.getElementById('project-detail').classList.remove('active');
  document.getElementById('main-page').style.display = '';
  runLoadingScreen(LOADING_MESSAGES_RETURN, 18, () => {
    // nothing extra needed — main page already visible
  });
}